{
  "sentences": [
    {
      "text": "這個便當要微波嗎？",
      "pinyin": "Zhège biàndāng yào wēibō ma?",
      "pinyin_numeric": "zhe4 ge5 bian4 dang1 yao4 wei1 bo1 ma0",
      "translation_en": "Does this bento need to be microwaved?",
      "translation_ko": "이 도시락을 전자레인지에 데워야 하나요?"
    },
    {
      "text": "那個三明治多少錢？",
      "pinyin": "Nàge sānmíngzhì duōshǎo qián?",
      "pinyin_numeric": "na4 ge5 san1 ming2 zhi4 duo1 shao3 qian2",
      "translation_en": "How much is that sandwich?",
      "translation_ko": "저 샌드위치는 얼마인가요?"
    },
    {
      "text": "這個飯糰跟那個茶葉蛋，總共多少？",
      "pinyin": "Zhège fàntuán gēn nàge cháyèdàn, zǒnggòng duōshǎo?",
      "pinyin_numeric": "zhe4 ge5 fan4 tuan2 gen1 na4 ge5 cha2 ye4 dan4, zong3 gong4 duo1 shao3",
      "translation_en": "This rice ball and that tea egg, how much in total?",
      "translation_ko": "이 주먹밥과 그 차란, 총 얼마인가요?"
    },
    {
      "text": "我要買這個泡麵跟那瓶礦泉水。",
      "pinyin": "Wǒ yào mǎi zhège pàomiàn gēn nà píng kuàngquánshuǐ.",
      "pinyin_numeric": "wo3 yao4 mai3 zhe4 ge5 pao4 mian4 gen1 na4 ping2 kuang4 quan2 shui3",
      "translation_en": "I want to buy this instant noodle and that bottle of mineral water.",
      "translation_ko": "이 라면과 그 생수 한 병을 사고 싶어요."
    },
    {
      "text": "這個優格有特價嗎？",
      "pinyin": "Zhège yōugé yǒu tèjià ma?",
      "pinyin_numeric": "zhe4 ge5 you1 ge2 you3 te4 jia4 ma0",
      "translation_en": "Is this yogurt on sale?",
      "translation_ko": "이 요구르트는 특가인가요?"
    },
    {
      "text": "那個餅乾是買一送一嗎？",
      "pinyin": "Nàge bǐnggān shì mǎi yī sòng yī ma?",
      "pinyin_numeric": "na4 ge5 bing3 gan1 shi4 mai3 yi1 song4 yi1 ma0",
      "translation_en": "Are those cookies buy one get one free?",
      "translation_ko": "그 과자는 하나 사면 하나 무료인가요?"
    },
    {
      "text": "這個口罩跟那個雨傘，我要結帳。",
      "pinyin": "Zhège kǒuzhào gēn nàge yǔsǎn, wǒ yào jiézhàng.",
      "pinyin_numeric": "zhe4 ge5 kou3 zhao4 gen1 na4 ge5 yu3 san3, wo3 yao4 jie2 zhang4",
      "translation_en": "This mask and that umbrella, I want to check out.",
      "translation_ko": "이 마스크와 그 우산, 계산하고 싶어요."
    },
    {
      "text": "這個電池跟那條充電線，我要用信用卡付款。",
      "pinyin": "Zhège diànchí gēn nà tiáo chōngdiànxiàn, wǒ yào yòng xìnyòngkǎ fùkuǎn.",
      "pinyin_numeric": "zhe4 ge5 dian4 chi2 gen1 na4 tiao2 chong1 dian4 xian4, wo3 yao4 yong4 xin4 yong4 ka3 fu4 kuan3",
      "translation_en": "This battery and that charging cable, I want to pay by credit card.",
      "translation_ko": "이 배터리와 그 충전 케이블, 신용카드로 결제할게요."
    },
    {
      "text": "請問，這個便當需要加熱嗎？",
      "pinyin": "Qǐngwèn, zhège biàndāng xūyào jiārè ma?",
      "pinyin_numeric": "qing3 wen4, zhe4 ge5 bian4 dang1 xu1 yao4 jia1 re4 ma0",
      "translation_en": "Excuse me, does this bento need to be heated?",
      "translation_ko": "실례합니다, 이 도시락을 데워야 하나요?"
    },
    {
      "text": "那個環保袋跟這個塑膠袋，我要哪一個？",
      "pinyin": "Nàge huánbǎo dài gēn zhège sùjiāo dài, wǒ yào nǎ yīge?",
      "pinyin_numeric": "na4 ge5 huan2 bao3 dai4 gen1 zhe4 ge5 su4 jiao1 dai4, wo3 yao4 na3 yi1 ge5",
      "translation_en": "That eco-friendly bag and this plastic bag, which one should I take?",
      "translation_ko": "그 친환경 봉투와 이 비닐봉투, 어떤 걸 골라야 할까요?"
    }
  ]
}
